// Poll all per-channel tables for Status = 'Ready To Queue' with no linked Content Queue record.
// COUNTA({Content Calendar}) = 0 prevents double-processing without needing a 'Queued' status.

const BASE_ID = $env.AIRTABLE_BASE_ID;
const API_KEY = $env.AIRTABLE_API_KEY;

const TABLES = [
  { id: 'tbl0w082lUb6OcwwQ', name: 'LinkedIn Posts',    platform: 'LinkedIn'  },
  { id: 'tblO58c8jXi1Ahipn', name: 'Twitter Posts',     platform: 'Twitter'   },
  { id: 'tblYwb4BkHg7rGshQ', name: 'Instagram Content', platform: 'Instagram' },
  { id: 'tbl0PY35chjkvynO1', name: 'SEO Articles',      platform: 'Blog'      },
  { id: 'tblExlqtrAup18AOd', name: 'Email Campaigns',   platform: 'Email'     }
];

const headers = {
  'Authorization': `Bearer ${API_KEY}`,
  'Content-Type': 'application/json'
};

const allItems = [];

for (const table of TABLES) {
  const filter = `AND({Status} = 'Ready To Queue', COUNTA({Content Calendar}) = 0)`;
  const url = `https://api.airtable.com/v0/${BASE_ID}/${table.id}` +
    `?filterByFormula=${encodeURIComponent(filter)}` +
    `&fields[]=Title&fields[]=Body&fields[]=Hashtags&fields[]=CTA` +
    `&fields[]=ImageUrl&fields[]=ContentType&fields[]=Hook` +
    `&fields[]=TargetKeyword&fields[]=PreviewText`;

  const response = await $http.request({ method: 'GET', url, headers });
  const records = response.records || [];

  for (const record of records) {
    allItems.push({
      json: {
        sourceTableId:   table.id,
        sourceTableName: table.name,
        sourceRecordId:  record.id,
        platform:        table.platform,
        fields:          record.fields
      }
    });
  }
}

return allItems;

const { platform, fields, sourceTableId, sourceRecordId } = $input.item.json;

const headline = fields.Title || '';

const rawType = (fields.ContentType || '').toLowerCase().trim();
const TYPE_MAP = {
  'carousel':       'carousel',
  'article':        'article',
  'post':           'post',
  'thread':         'thread',
  'reel':           'reel',
  'story':          'story',
  'email':          'email',
  'blog_post':      'blog_post',
  'blog post':      'blog_post',
  'executive_post': 'executive_post',
  'executive post': 'executive_post'
};
const contentType = TYPE_MAP[rawType] || 'post';

const mediaNotes = [fields.Hook, fields.VisualDirection].filter(Boolean).join('\n\n') || '';

return {
  json: {
    Headline:         headline,
    Body:             fields.Body || '',
    Hashtags:         fields.Hashtags || '',
    CTA:              fields.CTA || '',
    ImageUrl:         fields.ImageUrl || '',
    'Media Notes':    mediaNotes,
    Platform:         platform,
    'Content Type':   contentType,
    Status:           'Pending Review',
    'Pillar Topic':   fields.TargetKeyword || '',
    _sourceTableId:   sourceTableId,
    _sourceRecordId:  sourceRecordId
  }
};
